<?php
/**
 * Value object representing a blog post generated by an AI provider.
 *
 * @package ChangelogToBlogPost\AI
 */

namespace TenUp\ChangelogToBlogPost\AI;

/**
 * Immutable output of a successful AI generation call.
 */
readonly class GeneratedPost {

	/**
	 * @param string $title         Generated post title.
	 * @param string $content       Generated post body (HTML).
	 * @param string $provider_slug Provider slug that produced this post (e.g. 'openai').
	 */
	public function __construct(
		public string $title,
		public string $content,
		public string $provider_slug,
	) {}
}
